function closeSettingsModal() {
  document.querySelector(`.${SETTINGS_CLASS}__backdrop`)?.remove();
}

function createSettingsField(labelText, input) {
  const fieldEl = document.createElement("div");
  fieldEl.className = `${SETTINGS_CLASS}__field`;
  const label = document.createElement("label");
  label.textContent = labelText;
  fieldEl.append(label, input);
  return fieldEl;
}

async function openSettingsModal() {
  closeDestinationMenu();
  injectSettingsStyles();

  let destinations = [...(await loadAllDestinations())];
  const backdrop = document.createElement("div");
  backdrop.className = `${SETTINGS_CLASS}__backdrop`;

  const dialog = document.createElement("div");
  dialog.className = `${SETTINGS_CLASS}__dialog`;
  applyXThemeVars(dialog);
  dialog.setAttribute("role", "dialog");
  dialog.setAttribute("aria-modal", "true");
  dialog.setAttribute("aria-label", "Discord channel settings");

  const header = document.createElement("div");
  header.className = `${SETTINGS_CLASS}__header`;
  const heading = document.createElement("h2");
  heading.textContent = "Discord channels";
  const closeBtn = document.createElement("button");
  closeBtn.type = "button";
  closeBtn.className = `${SETTINGS_CLASS}__close`;
  closeBtn.setAttribute("aria-label", "Close");
  closeBtn.textContent = "×";
  closeBtn.addEventListener("click", closeSettingsModal);
  header.append(heading, closeBtn);

  const body = document.createElement("div");
  body.className = `${SETTINGS_CLASS}__body`;

  const hint = document.createElement("p");
  hint.className = `${SETTINGS_CLASS}__hint`;
  hint.textContent = "Create webhooks in Discord: Channel settings → Integrations → Webhooks. Channels are saved in Violentmonkey (or Tampermonkey) and persist across script updates — do not put webhook URLs in the script source.";
  body.append(hint);

  const listEl = document.createElement("div");
  listEl.className = `${SETTINGS_CLASS}__list`;
  body.append(listEl);

  function renderList() {
    listEl.replaceChildren();
    if (destinations.length === 0) {
      const emptyEl = document.createElement("div");
      emptyEl.className = `${SETTINGS_CLASS}__empty`;
      emptyEl.textContent = "No channels yet. Add one below.";
      listEl.append(emptyEl);
      return;
    }

    destinations.forEach((destination, index) => {
      const card = document.createElement("div");
      card.className = `${SETTINGS_CLASS}__card`;

      const head = document.createElement("div");
      head.className = `${SETTINGS_CLASS}__card-head`;

      const meta = document.createElement("div");
      const titleEl = document.createElement("div");
      titleEl.className = `${SETTINGS_CLASS}__card-title`;
      titleEl.textContent = destination.label;
      const idEl = document.createElement("div");
      idEl.className = `${SETTINGS_CLASS}__card-id`;
      idEl.textContent = destination.id;
      meta.append(titleEl, idEl);

      const removeBtn = document.createElement("button");
      removeBtn.type = "button";
      removeBtn.className = `${SETTINGS_CLASS}__remove`;
      removeBtn.textContent = "Remove";
      removeBtn.addEventListener("click", () => {
        destinations = destinations.filter((_, itemIndex) => itemIndex !== index);
        renderList();
      });
      head.append(meta, removeBtn);

      const labelInput = document.createElement("input");
      labelInput.type = "text";
      labelInput.value = destination.label;
      labelInput.addEventListener("input", () => {
        destinations[index].label = labelInput.value;
      });

      const urlInput = document.createElement("input");
      urlInput.type = "url";
      urlInput.placeholder = "https://discord.com/api/webhooks/...";
      urlInput.value = destination.webhookUrl;
      urlInput.addEventListener("input", () => {
        destinations[index].webhookUrl = urlInput.value.trim();
      });

      card.append(head, createSettingsField("Display name", labelInput), createSettingsField("Webhook URL", urlInput));
      listEl.append(card);
    });
  }

  const addSection = document.createElement("div");
  addSection.className = `${SETTINGS_CLASS}__card`;
  const addTitleEl = document.createElement("div");
  addTitleEl.className = `${SETTINGS_CLASS}__card-title`;
  addTitleEl.textContent = "Add channel";

  const newLabelInput = document.createElement("input");
  newLabelInput.type = "text";
  newLabelInput.placeholder = "Friends server";

  const newUrlInput = document.createElement("input");
  newUrlInput.type = "url";
  newUrlInput.placeholder = "https://discord.com/api/webhooks/...";

  const addBtn = document.createElement("button");
  addBtn.type = "button";
  addBtn.className = `${SETTINGS_CLASS}__btn ${SETTINGS_CLASS}__btn--ghost`;
  addBtn.textContent = "Add to list";
  addBtn.addEventListener("click", () => {
    const label = newLabelInput.value.trim();
    const webhookUrl = newUrlInput.value.trim();
    if (!label) {
      showToast("Enter a display name.", "error");
      return;
    }
    if (!isValidWebhookUrl(webhookUrl)) {
      showToast("Enter a valid Discord webhook URL.", "error");
      return;
    }
    const existingIds = new Set(destinations.map((item) => item.id));
    destinations.push({
      id: createDestinationId(label, existingIds),
      label,
      webhookUrl
    });
    newLabelInput.value = "";
    newUrlInput.value = "";
    renderList();
  });

  addSection.append(
    addTitleEl,
    createSettingsField("Display name", newLabelInput),
    createSettingsField("Webhook URL", newUrlInput),
    addBtn
  );
  body.append(addSection);

  const footer = document.createElement("div");
  footer.className = `${SETTINGS_CLASS}__footer`;

  const cancelBtn = document.createElement("button");
  cancelBtn.type = "button";
  cancelBtn.className = `${SETTINGS_CLASS}__btn ${SETTINGS_CLASS}__btn--ghost`;
  cancelBtn.textContent = "Cancel";
  cancelBtn.addEventListener("click", closeSettingsModal);

  const saveBtn = document.createElement("button");
  saveBtn.type = "button";
  saveBtn.className = `${SETTINGS_CLASS}__btn ${SETTINGS_CLASS}__btn--primary`;
  saveBtn.textContent = "Save";
  saveBtn.addEventListener("click", async () => {
    const sanitized = sanitizeDestinations(destinations);
    if (sanitized.length === 0 && destinations.length > 0) {
      showToast("Fix invalid names or webhook URLs before saving.", "error");
      return;
    }
    try {
      await saveAllDestinations(sanitized);
      showToast("Channels saved.", "success");
      closeSettingsModal();
      refreshShareButtons();
    } catch (error) {
      showToast(error.message, "error");
    }
  });

  footer.append(cancelBtn, saveBtn);
  dialog.append(header, body, footer);
  backdrop.append(dialog);
  backdrop.addEventListener("click", (event) => {
    if (event.target === backdrop) closeSettingsModal();
  });

  const onEscape = (event) => {
    if (event.key === "Escape") {
      closeSettingsModal();
      document.removeEventListener("keydown", onEscape);
    }
  };
  document.addEventListener("keydown", onEscape);

  document.body.append(backdrop);
  renderList();
  newLabelInput.focus();
}

function refreshShareButtons() {
  removeLegacyDiscordButtons();
}

function registerSettingsMenuCommand() {
  const register = typeof GM !== "undefined" && typeof GM.registerMenuCommand === "function"
    ? GM.registerMenuCommand.bind(GM)
    : typeof GM_registerMenuCommand === "function"
      ? GM_registerMenuCommand
      : null;

  if (!register) return;
  register("Discord channels…", () => openSettingsModal());
}

registerSettingsMenuCommand();

  // --- 12-preview.js ---
function embedColorCss(color) {
  if (typeof color !== "number") return "#5865f2";
  return `#${(color >>> 0).toString(16).padStart(6, "0").slice(-6)}`;
}

function appendLinkText(container, value) {
  const text = String(value || "").trim();
  if (!text) return;

  const masked = /^\[([^\]]+)\]\((https?:\/\/[^)]+)\)$/i.exec(text);
  if (masked) {
    const link = document.createElement("a");
    link.className = `${PREVIEW_CLASS}__link`;
    link.href = masked[2];
    link.textContent = masked[1];
    link.target = "_blank";
    link.rel = "noopener noreferrer";
    container.append(link);
    return;
  }

  if (/^https?:\/\//i.test(text)) {
    const link = document.createElement("a");
    link.className = `${PREVIEW_CLASS}__link`;
    link.href = text;
    link.textContent = text;
    link.target = "_blank";
    link.rel = "noopener noreferrer";
    container.append(link);
    return;
  }

  container.textContent = text;
}

function createPreviewEmbed(embed) {
  const card = document.createElement("article");
  card.className = `${PREVIEW_CLASS}__embed`;
  card.style.setProperty("--tds-preview-accent", embedColorCss(embed.color));

  if (embed.author?.name) {
    const author = document.createElement("div");
    author.className = `${PREVIEW_CLASS}__author`;

    if (embed.author.icon_url) {
      const icon = document.createElement("img");
      icon.className = `${PREVIEW_CLASS}__author-icon`;
      icon.src = embed.author.icon_url;
      icon.alt = "";
      icon.loading = "lazy";
      icon.referrerPolicy = "no-referrer";
      author.append(icon);
    }

    const name = document.createElement("span");
    name.className = `${PREVIEW_CLASS}__author-name`;
    if (embed.author.url) {
      const link = document.createElement("a");
      link.className = `${PREVIEW_CLASS}__link`;
      link.href = embed.author.url;
      link.textContent = embed.author.name;
      link.target = "_blank";
      link.rel = "noopener noreferrer";
      name.append(link);
    } else {
      name.textContent = embed.author.name;
    }

    author.append(name);
    card.append(author);
  }

  if (embed.title) {
    const title = document.createElement("div");
    title.className = `${PREVIEW_CLASS}__title`;
    title.textContent = embed.title;
    card.append(title);
  }

  if (embed.description) {
    const description = document.createElement("div");
    description.className = `${PREVIEW_CLASS}__description`;
    description.textContent = embed.description;
    card.append(description);
  }

  if (embed.image?.url) {
    const imageWrap = document.createElement("div");
    imageWrap.className = `${PREVIEW_CLASS}__image-wrap`;
    const image = document.createElement("img");
    image.className = `${PREVIEW_CLASS}__image`;
    image.src = embed.image.url;
    image.alt = "";
    image.loading = "lazy";
    image.referrerPolicy = "no-referrer";
    imageWrap.append(image);
    card.append(imageWrap);
  }

  for (const field of embed.fields || []) {
    const fieldEl = document.createElement("div");
    fieldEl.className = `${PREVIEW_CLASS}__field`;

    const name = document.createElement("div");
    name.className = `${PREVIEW_CLASS}__field-name`;
    name.textContent = field.name || "";

    const value = document.createElement("div");
    value.className = `${PREVIEW_CLASS}__field-value`;
    appendLinkText(value, field.value);

    fieldEl.append(name, value);
    card.append(fieldEl);
  }

  if (embed.footer?.text) {
    const footer = document.createElement("div");
    footer.className = `${PREVIEW_CLASS}__footer`;
    footer.textContent = embed.footer.text;
    card.append(footer);
  }

  return card;
}

function createPreviewMessage(payload, index, total) {
  const message = document.createElement("div");
  message.className = `${PREVIEW_CLASS}__message`;

  if (total > 1) {
    const label = document.createElement("div");
    label.className = `${PREVIEW_CLASS}__message-label`;
    label.textContent = `Message ${index + 1} of ${total}`;
    message.append(label);
  }

  if (payload.username || payload.avatar_url) {
    const header = document.createElement("div");
    header.className = `${PREVIEW_CLASS}__webhook`;

    if (payload.avatar_url) {
      const avatar = document.createElement("img");
      avatar.className = `${PREVIEW_CLASS}__webhook-avatar`;
      avatar.src = payload.avatar_url;
      avatar.alt = "";
      avatar.loading = "lazy";
      avatar.referrerPolicy = "no-referrer";
      header.append(avatar);
    }

    const name = document.createElement("span");
    name.className = `${PREVIEW_CLASS}__webhook-name`;
    name.textContent = payload.username || WEBHOOK_SENDER_NAME;
    header.append(name);
    message.append(header);
  }

  if (payload.content) {
    const content = document.createElement("div");
    content.className = `${PREVIEW_CLASS}__content`;
    content.textContent = payload.content;
    message.append(content);
  }

  for (const embed of payload.embeds || []) {
    message.append(createPreviewEmbed(embed));
  }

  return message;
}

function renderDiscordPreview(payloads) {
  const host = document.createElement("div");
  host.className = PREVIEW_CLASS;
  const list = Array.isArray(payloads) ? payloads : [];

  if (!list.length) {
    const empty = document.createElement("p");
    empty.className = `${PREVIEW_CLASS}__empty`;
    empty.textContent = "Nothing to preview for this post.";
    host.append(empty);
    return host;
  }

  list.forEach((payload, index) => {
    host.append(createPreviewMessage(payload, index, list.length));
  });

  return host;
}

